namespace sv_3790e11c84d44085b2540069ea89da45.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_3790e11c84d44085b2540069ea89da45.Services

<button class="reaction-badge" @onclick="HandleClick" title="@string.Join(", ", Reaction.Users)">
    <span class="reaction-emoji">@Reaction.Emoji</span>
    <span class="reaction-count">@Reaction.Users.Count</span>
</button>

@code {
    [Parameter, EditorRequired] public Reaction Reaction { get; set; } = default!;
    [Parameter] public EventCallback OnClick { get; set; }

    private async Task HandleClick() => await OnClick.InvokeAsync();
}

@using sv_3790e11c84d44085b2540069ea89da45.Services

<div class="message-item" @onmouseenter="ShowActions" @onmouseleave="HideActions">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time" title="@Message.SentAt.ToString("f")">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <ReactionBadge Reaction="reaction"
                               OnClick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))" />
            }
        </div>
    }

    @if (ThreadSummary is not null)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            💬 @ThreadSummary.ReplyCount @(ThreadSummary.ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😀 React
            </button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadSummary { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private void ShowActions() => showActions = true;

    private void HideActions()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    internal static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 30) return "just now";
        if (diff.TotalMinutes < 1) return $"{(int)diff.TotalSeconds}s ago";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

@using sv_3790e11c84d44085b2540069ea89da45.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="() => OnClick.InvokeAsync(Channel)">
    <div class="channel-name-row">
        <span class="channel-name"><span class="channel-hash">#</span> @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <div class="channel-desc">@Truncate(Channel.Description, 40)</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<Channel> OnClick { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length > maxLength ? string.Concat(text.AsSpan(0, maxLength - 3), "...") : text;
}

@using sv_3790e11c84d44085b2540069ea89da45.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h5>💬 Channels</h5>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnClick="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<Channel> OnChannelSelected { get; set; }
}

@using sv_3790e11c84d44085b2540069ea89da45.Services

<div class="thread-panel">
    <div class="thread-header">
        <h6>Thread</h6>
        <button class="btn-close btn-close-sm" @onclick="OnClose" aria-label="Close thread"></button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-quote">
            <div class="message-author">@RootMessage.Author</div>
            <div class="message-content">@RootMessage.Content</div>
        </div>
    }

    <div class="thread-replies">
        @if (ThreadMessages.Count == 0)
        {
            <p class="text-muted text-center mt-3">No replies yet</p>
        }
        else
        {
            @foreach (var reply in ThreadMessages)
            {
                <MessageItem Message="reply" />
            }
        }
    </div>

    <MessageInput Placeholder="Reply in thread..." ButtonText="Reply" OnSend="OnSendReply" />
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
}

