@layout ChatLayout
@rendermode InteractiveServer
@using sv_3790e11c84d44085b2540069ea89da45.Services
@using sv_3790e11c84d44085b2540069ea89da45.Components.Chat
@inject IChatService ChatService

<HeadContent>
    <link rel="stylesheet" href="css/chat.css" />
</HeadContent>

<div class="chat-container">
    <ChannelSidebar Channels="channels"
                    SelectedChannelId="selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="message-area @(isThreadOpen ? "" : "expanded")">
        @if (selectedChannel is not null)
        {
            <div class="area-header">
                <h5># @selectedChannel.Name</h5>
                <span class="header-desc">@selectedChannel.Description</span>
            </div>

            <div class="message-list">
                @if (hasMoreMessages)
                {
                    <button class="btn btn-link btn-sm load-more-btn" @onclick="LoadOlderMessages"
                            disabled="@isLoadingMore">
                        @(isLoadingMore ? "Loading…" : "↑ Load older messages")
                    </button>
                }

                @foreach (var message in messages)
                {
                    <MessageItem Message="message"
                                 ThreadSummary="GetThreadSummary(message.Id)"
                                 OnOpenThread="OpenThread"
                                 OnReact="HandleReaction" />
                }
            </div>

            <MessageInput Placeholder="@($"Message #{selectedChannel.Name}")" OnSend="SendMessage" />
        }
        else
        {
            <div class="no-channel">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

