@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_3790e11c84d44085b2540069ea89da45.Services
@using sv_3790e11c84d44085b2540069ea89da45.Components.Chat
@inject IChatService ChatService

<HeadContent>
    <link rel="stylesheet" href="css/chat.css" />
</HeadContent>

<div class="chat-container">
    <ChannelSidebar Channels="channels"
                    SelectedChannelId="selectedChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="message-area @(isThreadOpen ? "" : "expanded")">
        @if (selectedChannel is not null)
        {
            <div class="area-header">
                <h5># @selectedChannel.Name</h5>
                <span class="header-desc">@selectedChannel.Description</span>
            </div>

            <div class="message-list">
                @if (hasMoreMessages)
                {
                    <button class="btn btn-link btn-sm load-more-btn" @onclick="LoadOlderMessages"
                            disabled="@isLoadingMore">
                        @(isLoadingMore ? "Loading…" : "↑ Load older messages")
                    </button>
                }

                @foreach (var message in messages)
                {
                    <MessageItem Message="message"
                                 ThreadSummary="GetThreadSummary(message.Id)"
                                 OnOpenThread="OpenThread"
                                 OnReact="HandleReaction" />
                }
            </div>

            <MessageInput Placeholder="@($"Message #{selectedChannel.Name}")" OnSend="SendMessage" />
        }
        else
        {
            <div class="no-channel">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (isThreadOpen)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     ThreadMessages="threadMessages"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? selectedChannel;
    private int selectedChannelId;
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadMessages = [];

    private bool hasMoreMessages = true;
    private bool isLoadingMore;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        selectedChannel = channel;
        selectedChannelId = channel.Id;
        messages = [];
        hasMoreMessages = true;
        isThreadOpen = false;
        threadRootMessage = null;
        threadMessages = [];

        await LoadMessages();
        await ChatService.MarkChannelReadAsync(channel.Id);

        var idx = channels.FindIndex(c => c.Id == channel.Id);
        if (idx >= 0)
        {
            channels[idx] = channel with { UnreadCount = 0 };
        }
    }

    private async Task LoadMessages()
    {
        var loaded = await ChatService.GetMessagesAsync(selectedChannelId, messages.Count, PageSize);
        hasMoreMessages = loaded.Count >= PageSize;
        messages.InsertRange(0, loaded);
        RebuildThreadSummaries();
    }

    private async Task LoadOlderMessages()
    {
        isLoadingMore = true;
        await LoadMessages();
        isLoadingMore = false;
    }

    private void RebuildThreadSummaries()
    {
        threadSummaries.Clear();
        var replies = messages.Where(m => m.ReplyToId.HasValue);
        foreach (var group in replies.GroupBy(m => m.ReplyToId!.Value))
        {
            threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt));
        }
    }

    private ThreadSummary? GetThreadSummary(int messageId) =>
        threadSummaries.GetValueOrDefault(messageId);

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;
        var message = await ChatService.SendMessageAsync(selectedChannelId, content, null);
        messages.Add(message);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null || selectedChannel is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannelId, content, threadRootMessage.Id);
        threadMessages.Add(reply);
        messages.Add(reply);
        RebuildThreadSummaries();
    }

    private async Task HandleReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);

        var msg = messages.FirstOrDefault(m => m.Id == reaction.MessageId);
        if (msg is null) return;

        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == reaction.Emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(reaction.Emoji, ["You"]));
        }
    }
}

