toolArgs.file_text:
/* ===== Chat Layout ===== */
.chat-container {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    background: #f8f9fa;
}

/* ===== Channel Sidebar ===== */
.channel-sidebar {
    width: 260px;
    min-width: 220px;
    background: #2c2f33;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #40444b;
}

.sidebar-header h5 {
    margin: 0;
    color: #fff;
    font-size: 1rem;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 4px;
    margin: 1px 8px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background: #36393f;
}

.channel-item.active {
    background: #40444b;
    color: #fff;
}

.channel-name-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-weight: 500;
    font-size: 0.9rem;
}

.channel-hash {
    opacity: 0.6;
    margin-right: 2px;
}

.unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
